package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;
import java.lang.reflect.Modifier;

public class CSVFormatTest {

    private CSVFormat createCSVFormatWithQuoteCharacter(Character quoteCharacter) throws Exception {
        // Use the withQuote method to create a new instance with the desired quoteCharacter
        return CSVFormat.DEFAULT.withQuote(quoteCharacter);
    }

    @Test
    void testIsQuoteCharacterSet_whenQuoteCharacterIsSet() throws Exception {
        CSVFormat csvFormat = createCSVFormatWithQuoteCharacter('\"');
        boolean result = csvFormat.isQuoteCharacterSet();
        assertTrue(result);
    }

    @Test
    void testIsQuoteCharacterSet_whenQuoteCharacterIsNull() throws Exception {
        CSVFormat csvFormat = createCSVFormatWithQuoteCharacter(null);
        boolean result = csvFormat.isQuoteCharacterSet();
        assertFalse(result);
    }
}
